    | "blocked";
  result?: ImplementorResult;
  errors: CliError[];
  warnings: string[];
}

function blockedError(code: string, message: string, detail?: string): CliError {
  return {
    code,
    message,
    ...(detail ? { detail } : {}),
  };
}

async function prepareStoryContext(input: {
  specPackRoot: string;
  storyId: string;
  configPath?: string;
  providerOverride?: ProviderName;
}): Promise<PreparedStoryContext | WorkflowFailure> {
  const inspection = await inspectSpecPack(input.specPackRoot);
  if (inspection.status !== "ready") {
    return {
      outcome: "blocked",
      errors: [
        blockedError(
          "INVALID_SPEC_PACK",
          "Spec-pack inspection must be ready before story implementation can start.",
          inspection.blockers.join("; ") || inspection.notes.join("; ")
        ),
      ],
    };
  }

  const story = inspection.stories.find((candidate) => candidate.id === input.storyId);
  if (!story) {
    return {
      outcome: "blocked",
      errors: [
        blockedError(
          "INVALID_SPEC_PACK",
          `Story '${input.storyId}' was not found in the resolved story inventory.`
        ),
      ],
    };
  }

  const config = await loadRunConfig({
    specPackRoot: inspection.specPackRoot,
    configPath: input.configPath,
  });
  const gateResolution = await resolveVerificationGates({
    specPackRoot: inspection.specPackRoot,
  });
  if (gateResolution.status !== "ready" || !gateResolution.verificationGates) {
    return {
      outcome: "blocked",
      errors: gateResolution.errors.length
        ? gateResolution.errors
        : [
            blockedError(
              "VERIFICATION_GATE_UNRESOLVED",
              "Verification gates must be resolved before story implementation can start."
            ),
          ],
    };
  }

  const provider =
    input.providerOverride ??
    (config.story_implementor.secondary_harness === "none"
      ? "claude-code"
      : config.story_implementor.secondary_harness);

  return {
    specPackRoot: inspection.specPackRoot,
    story: {
      id: story.id,
      title: story.title,
      path: story.path,
    },
    provider,
    model: config.story_implementor.model,
    reasoningEffort: config.story_implementor.reasoning_effort,
    implementationPromptInsertPath:
      inspection.inserts.customStoryImplPromptInsert === "present"
        ? join(inspection.specPackRoot, "custom-story-impl-prompt-insert.md")
        : undefined,
    gateCommands: {
      story: gateResolution.verificationGates.storyGate,
      epic: gateResolution.verificationGates.epicGate,
    },
    paths: {
      epicPath: inspection.artifacts.epicPath,
      techDesignPath: inspection.artifacts.techDesignPath,
      techDesignCompanionPaths: inspection.artifacts.techDesignCompanionPaths,
      testPlanPath: inspection.artifacts.testPlanPath,
    },
    selfReviewPasses: config.self_review.passes,
  };
}

function executionFailureError(input: {
  provider: ProviderName;
  stderr: string;
  errorCode?: string;
}): CliError {
  if (input.errorCode === "ENOENT") {
    return blockedError(
      "PROVIDER_UNAVAILABLE",
      `Provider executable is unavailable for ${input.provider}.`,
      input.stderr
    );
  }

  return blockedError(
    "PROVIDER_UNAVAILABLE",
    `Provider execution failed for ${input.provider}.`,
    input.stderr
  );
}

function buildImplementorResult(input: {
  provider: ProviderName;
  model: string;
  sessionId: string;
  story: PreparedStoryContext["story"];
  payload: ProviderPayload;
  passesRun: number;
}): ImplementorResult {
  return {
    resultId: randomUUID(),
    provider: input.provider,
    model: input.model,
    role: "story_implementor",
    sessionId: input.sessionId,
    continuation: {
      provider: input.provider,
      sessionId: input.sessionId,
      storyId: input.story.id,
    },
    outcome: input.payload.outcome,
    story: {
      id: input.story.id,
      title: input.story.title,
    },
    planSummary: input.payload.planSummary,
    changedFiles: input.payload.changedFiles,
    tests: input.payload.tests,
    gatesRun: input.payload.gatesRun,
    selfReview: {
      passesRun: input.passesRun,
      findingsFixed: input.payload.selfReview.findingsFixed,
      findingsSurfaced: input.payload.selfReview.findingsSurfaced,
    },
    openQuestions: input.payload.openQuestions,
    specDeviations: input.payload.specDeviations,
    recommendedNextStep: input.payload.recommendedNextStep,
  };
}

async function executePrompt(input: {
  provider: ProviderName;
  specPackRoot: string;
  model: string;
  reasoningEffort: string;
  prompt: string;
  resumeSessionId?: string;
  env?: Record<string, string | undefined>;
}): Promise<PromptExecutionSuccess | PromptExecutionFailure> {
  const adapter = createProviderAdapter(input.provider, {
    env: input.env,
  });
  const execution = await adapter.execute({
    prompt: input.prompt,
    cwd: input.specPackRoot,
    model: input.model,
    reasoningEffort: input.reasoningEffort,
    resumeSessionId: input.resumeSessionId,
    timeoutMs: 30_000,
    resultSchema: providerPayloadSchema,
  });

  if (execution.exitCode !== 0) {
    return {
      outcome: "blocked" as const,
      errors: [
        executionFailureError({
          provider: input.provider,
          stderr: execution.stderr,
          errorCode: execution.errorCode,
        }),
      ],
    };
  }

  if (execution.parseError || !execution.parsedResult) {
    return {
      outcome: "blocked" as const,
      errors: [
        blockedError(
          "PROVIDER_OUTPUT_INVALID",
          `Provider output was invalid for ${input.provider}.`,
          execution.parseError
        ),
      ],
    };
  }

  const sessionId = execution.sessionId ?? input.resumeSessionId;
  if (!sessionId) {
    return {
      outcome: "blocked" as const,
      errors: [
        blockedError(
          "CONTINUATION_HANDLE_INVALID",
          `Provider ${input.provider} did not return a session id for a retained implementor workflow.`
        ),
      ],
    };
  }

import { basename } from "node:path";

import { pathExists, readTextFile } from "./fs-utils";
import {
  getEmbeddedPromptAssets,
  type BasePromptId,
  type SnippetId,
} from "./prompt-assets";

const MAX_PUBLIC_INSERT_BYTES = 64 * 1024;

interface SharedPromptInput {
  storyId?: string;
  storyTitle?: string;
  storyPath?: string;
  epicPath?: string;
  techDesignPath?: string;
  techDesignCompanionPaths?: string[];
  testPlanPath?: string;
  gateCommands: {
    story?: string;
    epic?: string;
  };
}

export interface StoryImplementorPromptInput extends SharedPromptInput {
  role: "story_implementor";
  storyId: string;
  storyTitle: string;
  storyPath: string;
  implementationPromptInsertPath?: string;
  followupRequest?: string;
  selfReviewPass?: number;
}

export interface StoryVerifierPromptInput extends SharedPromptInput {
  role: "story_verifier";
  storyId: string;
  storyTitle: string;
  storyPath: string;
  verifierLabel: string;
  verifierPromptInsertPath?: string;
}

export interface QuickFixPromptInput extends SharedPromptInput {
  role: "quick_fixer";
  followupRequest: string;
  affectedScope: string;
}

export interface EpicVerifierPromptInput extends SharedPromptInput {
  role: "epic_verifier";
}

export interface EpicSynthesizerPromptInput extends SharedPromptInput {
  role: "epic_synthesizer";
}

export type PromptAssemblyInput =
  | StoryImplementorPromptInput
  | StoryVerifierPromptInput
  | QuickFixPromptInput
  | EpicVerifierPromptInput
  | EpicSynthesizerPromptInput;

export interface PromptAssemblyResult {
  prompt: string;
  basePromptId: BasePromptId;
  snippetIds: SnippetId[];
  publicInsertIds: string[];
}

function basePromptIdForRole(role: PromptAssemblyInput["role"]): BasePromptId {
  switch (role) {
    case "story_implementor":
      return "story-implementor";
    case "story_verifier":
      return "story-verifier";
    case "quick_fixer":
      return "quick-fixer";
    case "epic_verifier":
      return "epic-verifier";
    case "epic_synthesizer":
      return "epic-synthesizer";
  }
}

function snippetIdsForInput(input: PromptAssemblyInput): SnippetId[] {
  switch (input.role) {
    case "story_implementor": {
      const snippetIds: SnippetId[] = [
        "reading-journey",
        "gate-instructions",
        "report-contract",
      ];
      if (typeof input.selfReviewPass === "number" && input.selfReviewPass >= 1) {
        snippetIds.push(selfReviewSnippetId(input.selfReviewPass));
      }
      return snippetIds;
    }
    case "story_verifier":
      return [
        "reading-journey",
        "gate-instructions",
        "report-contract",
        "mock-audit",
      ];
    case "quick_fixer":
      return ["gate-instructions", "report-contract"];
    case "epic_verifier":
      return ["gate-instructions", "report-contract", "mock-audit"];
    case "epic_synthesizer":
      return ["gate-instructions", "report-contract"];
  }
}

function selfReviewSnippetId(pass: number): SnippetId {
  if (pass <= 1) {
    return "self-review-pass-1";
  }
  if (pass === 2) {
    return "self-review-pass-2";
  }
  return "self-review-pass-3";
}

function buildReadingJourney(input: PromptAssemblyInput): string {
  if (input.role === "quick_fixer") {
    return "";
  }

  const companionLines = (input.techDesignCompanionPaths ?? [])
    .map((path) => `- ${path}`)
    .join("\n");
  const common = [
    `- Story: ${input.storyPath ?? "n/a"}`,
    `- Epic: ${input.epicPath ?? "n/a"}`,
    `- Tech Design Index: ${input.techDesignPath ?? "n/a"}`,
    companionLines ? `- Tech Design Companions:\n${companionLines}` : "",
    `- Test Plan: ${input.testPlanPath ?? "n/a"}`,
  ]
    .filter(Boolean)
    .join("\n");

  if (input.role === "story_implementor") {
    return [
      "Read the current story first.",
      common,
      "Then read the full tech-design set before implementation starts.",
      "Read each file in 500-line chunks if large.",
      "Reflect after each chunk before you move on.",
    ].join("\n");
  }

  if (input.role === "story_verifier") {
    return [
      "Read the current story and the full tech-design set before you judge the implementation.",
      common,
      "As you read, extract AC and TC evidence.",
      "Then verify against code, tests, and artifacts before filing findings.",
      "Read each file in 500-line chunks if large.",
      "Reflect after each chunk before you move on.",
    ].join("\n");
  }

  return [
    "Read the epic-level artifacts before you judge the whole implementation set.",
    common,
  ].join("\n");
}

function resultContractName(input: PromptAssemblyInput): string {
  switch (input.role) {
    case "story_implementor":
      return "ImplementorResult";
    case "story_verifier":
      return "StoryVerifierResult";
    case "quick_fixer":
      return "QuickFixResult";
    case "epic_verifier":
      return "EpicVerifierResult";
    case "epic_synthesizer":
      return "EpicSynthesisResult";
  }
}

function routingGuidance(input: PromptAssemblyInput): string {
  switch (input.role) {
    case "story_verifier":
      return "Preserve the outcome, requirement coverage, and recommended fix scope for the orchestrator.";
    case "quick_fixer":
      return "Report whether the bounded fix is ready for verification or needs more routing.";
    case "epic_synthesizer":
      return "Keep confirmed issues separate from disputed or unconfirmed issues.";
    default:
      return "";
  }
}

function runtimeValues(input: PromptAssemblyInput): Record<string, string> {
  const values: Record<string, string> = {
    STORY_ID: input.storyId ?? "",
    STORY_TITLE: input.storyTitle ?? "",
    STORY_PATH: input.storyPath ?? "",
    EPIC_PATH: input.epicPath ?? "",
    TECH_DESIGN_PATH: input.techDesignPath ?? "",
    TEST_PLAN_PATH: input.testPlanPath ?? "",
    STORY_GATE_COMMAND: input.gateCommands.story ?? "not provided",
    EPIC_GATE_COMMAND: input.gateCommands.epic ?? "not provided",
    RESULT_CONTRACT_NAME: resultContractName(input),
    ROUTING_GUIDANCE: routingGuidance(input),
    READING_JOURNEY: buildReadingJourney(input),
    VERIFIER_LABEL: input.role === "story_verifier" ? input.verifierLabel : "",
    FOLLOWUP_REQUEST:
      input.role === "quick_fixer"
        ? input.followupRequest
        : input.role === "story_implementor"
          ? input.followupRequest ?? ""
          : "",
    AFFECTED_SCOPE: input.role === "quick_fixer" ? input.affectedScope : "",
  };

  if (input.role === "story_implementor" && input.selfReviewPass) {
    values.RESULT_CONTRACT_NAME = resultContractName(input);
  }
  return values;
}

function interpolateTemplate(
  template: string,
  values: Record<string, string>
): string {
  return template.replaceAll(/{{([A-Z_]+)}}/g, (_, key: string) => {
    return values[key] ?? "";
  });
}

async function loadPublicInsert(
  path: string | undefined
): Promise<{ assetId?: string; content?: string }> {
  if (!path || !(await pathExists(path))) {
    return {};
  }

  const file = Bun.file(path);
  if (file.size > MAX_PUBLIC_INSERT_BYTES) {
    throw new Error(`Public prompt insert exceeds ${MAX_PUBLIC_INSERT_BYTES} bytes: ${path}`);
  }

  return {
    assetId: basename(path),
    content: await readTextFile(path),
  };
}

function selfReviewSection(input: PromptAssemblyInput): string {
  if (input.role !== "story_implementor" || !input.selfReviewPass) {
    return "";
  }

  return {
    outcome: execution.parsedResult.outcome,
    sessionId,
    payload: execution.parsedResult,
  };
}

async function resolveContinuationOwner(input: {
  specPackRoot: string;
  provider: ProviderName;
  sessionId: string;
}): Promise<string | null> {
  const artifactsRoot = join(resolve(input.specPackRoot), "artifacts");
  if (!(await pathExists(artifactsRoot))) {
    return null;
  }

  const groups = await readdir(artifactsRoot, { withFileTypes: true });
  for (const group of groups) {
    if (!group.isDirectory()) {
      continue;
    }

    const groupPath = join(artifactsRoot, group.name);
    const entries = await readdir(groupPath, { withFileTypes: true });
    for (const entry of entries) {
      if (!entry.isFile() || !entry.name.endsWith(".json")) {
        continue;
      }

      try {
        const content = JSON.parse(
          await readTextFile(join(groupPath, entry.name))
        ) as {
          result?: {
            continuation?: {
              provider?: string;
              sessionId?: string;
              storyId?: string;
            };
          };
        };
        const continuation = content.result?.continuation;
        if (
          continuation?.provider === input.provider &&
          continuation?.sessionId === input.sessionId
        ) {
          return continuation.storyId ?? group.name;
        }
      } catch {}
    }
  }

  return null;
}

export async function validateContinuationHandle(input: {
  specPackRoot: string;
  storyId: string;
  provider: string;
  sessionId: string;
}): Promise<CliError | null> {
  const provider = providerIdSchema.safeParse(input.provider);
  if (!provider.success) {
    return blockedError(
      "CONTINUATION_HANDLE_INVALID",
      `Provider '${input.provider}' is not a valid continuation provider.`
    );
  }

  if (provider.data === "copilot") {
    return blockedError(
      "CONTINUATION_HANDLE_INVALID",
      "Provider 'copilot' cannot be used for retained story_implementor continuation sessions."
    );
  }

  const owner = await resolveContinuationOwner({
    specPackRoot: input.specPackRoot,
    provider: provider.data,
    sessionId: input.sessionId,
  });
  if (owner === input.storyId) {
    return null;
  }

  if (owner) {
    return blockedError(
      "CONTINUATION_HANDLE_INVALID",
      `Continuation handle ${input.sessionId} belongs to '${owner}', not '${input.storyId}'.`
    );
  }

  return blockedError(
    "CONTINUATION_HANDLE_INVALID",
    `Continuation handle ${input.sessionId} was not found for story '${input.storyId}'.`
  );
}

export async function runStoryImplement(input: {
  specPackRoot: string;
  storyId: string;
  configPath?: string;
  env?: Record<string, string | undefined>;
}): Promise<StoryWorkflowResult> {
  const context = await prepareStoryContext(input);
  if ("errors" in context) {
    return {
      outcome: "blocked",
      errors: context.errors,
      warnings: [],
    };
  }

  const prompt = await assemblePrompt({
    role: "story_implementor",
    storyId: context.story.id,
    storyTitle: context.story.title,
    storyPath: context.story.path,
    epicPath: context.paths.epicPath,
    techDesignPath: context.paths.techDesignPath,
    techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
    testPlanPath: context.paths.testPlanPath,
    gateCommands: context.gateCommands,
    implementationPromptInsertPath: context.implementationPromptInsertPath,
  });
  const initial = await executePrompt({
    provider: context.provider,
    specPackRoot: context.specPackRoot,
    model: context.model,
    reasoningEffort: context.reasoningEffort,
    prompt: prompt.prompt,
    env: input.env,
  });
  if ("errors" in initial) {
    return {
      outcome: "blocked",
      errors: initial.errors,
      warnings: [],
    };
  }

  let payload = initial.payload;
  let sessionId = initial.sessionId;
  let passesRun = 0;

  if (payload.outcome !== "blocked" && payload.outcome !== "needs-human-ruling") {
    for (let pass = 1; pass <= context.selfReviewPasses; pass += 1) {
      const reviewPrompt = await assemblePrompt({
        role: "story_implementor",
        storyId: context.story.id,
        storyTitle: context.story.title,
        storyPath: context.story.path,
        epicPath: context.paths.epicPath,
        techDesignPath: context.paths.techDesignPath,
        techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
        testPlanPath: context.paths.testPlanPath,
        gateCommands: context.gateCommands,
        implementationPromptInsertPath: context.implementationPromptInsertPath,
        selfReviewPass: pass,
      });
      const review = await executePrompt({
        provider: context.provider,
        specPackRoot: context.specPackRoot,
        model: context.model,
        reasoningEffort: context.reasoningEffort,
        prompt: reviewPrompt.prompt,
        resumeSessionId: sessionId,
        env: input.env,
      });
      if ("errors" in review) {
        return {
          outcome: "blocked",
          errors: review.errors,
          warnings: [],
        };
      }

      payload = review.payload;
      sessionId = review.sessionId;
      passesRun = pass;

      if (payload.outcome === "blocked" || payload.outcome === "needs-human-ruling") {
        break;
      }
    }
  }

  const result = buildImplementorResult({
    provider: context.provider,
    model: context.model,
    sessionId,
    story: context.story,
    payload,
    passesRun,
  });

  return {
    outcome: payload.outcome,
    result,
    errors: [],
    warnings: [],
  };
}

export async function runStoryContinue(input: {
  specPackRoot: string;
  storyId: string;
  provider: string;
  sessionId: string;
  followupRequest: string;
  configPath?: string;
  env?: Record<string, string | undefined>;
}): Promise<StoryWorkflowResult> {
  const continuationError = await validateContinuationHandle({
    specPackRoot: input.specPackRoot,
    storyId: input.storyId,
    provider: input.provider,
    sessionId: input.sessionId,
  });
  if (continuationError) {
    return {
      outcome: "blocked",
      errors: [continuationError],
      warnings: [],
    };
  }

  const provider = providerIdSchema.safeParse(input.provider);
  if (!provider.success) {
    return {
      outcome: "blocked",
      errors: [
        blockedError(
          "CONTINUATION_HANDLE_INVALID",
          `Provider '${input.provider}' is not valid for continuation.`
        ),
      ],
      warnings: [],
    };
  }

  const context = await prepareStoryContext({
    specPackRoot: input.specPackRoot,
    storyId: input.storyId,
    configPath: input.configPath,
    providerOverride: provider.data,
  });
  if ("errors" in context) {
    return {
      outcome: "blocked",
      errors: context.errors,
      warnings: [],
    };
  }

  const prompt = await assemblePrompt({
    role: "story_implementor",
    storyId: context.story.id,
    storyTitle: context.story.title,
    storyPath: context.story.path,
    epicPath: context.paths.epicPath,
    techDesignPath: context.paths.techDesignPath,
    techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
    testPlanPath: context.paths.testPlanPath,
    gateCommands: context.gateCommands,
    implementationPromptInsertPath: context.implementationPromptInsertPath,
    followupRequest: input.followupRequest,
  });
  const initial = await executePrompt({
    provider: provider.data,
    specPackRoot: context.specPackRoot,
    model: context.model,
    reasoningEffort: context.reasoningEffort,
    prompt: prompt.prompt,
    resumeSessionId: input.sessionId,
    env: input.env,
  });
  if ("errors" in initial) {
    return {
      outcome: "blocked",
      errors: initial.errors,
      warnings: [],
    };
  }

  let payload = initial.payload;
  let sessionId = initial.sessionId;
  let passesRun = 0;

  if (payload.outcome !== "blocked" && payload.outcome !== "needs-human-ruling") {
    for (let pass = 1; pass <= context.selfReviewPasses; pass += 1) {
      const reviewPrompt = await assemblePrompt({
        role: "story_implementor",
        storyId: context.story.id,
        storyTitle: context.story.title,
        storyPath: context.story.path,
        epicPath: context.paths.epicPath,
        techDesignPath: context.paths.techDesignPath,
        techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
        testPlanPath: context.paths.testPlanPath,
        gateCommands: context.gateCommands,
        implementationPromptInsertPath: context.implementationPromptInsertPath,
        selfReviewPass: pass,
      });
      const review = await executePrompt({
        provider: provider.data,
        specPackRoot: context.specPackRoot,
        model: context.model,
        reasoningEffort: context.reasoningEffort,
        prompt: reviewPrompt.prompt,
        resumeSessionId: sessionId,
        env: input.env,
      });
      if ("errors" in review) {
        return {
          outcome: "blocked",
          errors: review.errors,
          warnings: [],
        };

  return `Self-review pass ${input.selfReviewPass}`;
}

function followupSection(input: PromptAssemblyInput): string {
  if (input.role !== "story_implementor" || !input.followupRequest) {
    return "";
  }

  return `## Follow-up Request\n${input.followupRequest.trim()}`;
}

export async function assemblePrompt(
  input: PromptAssemblyInput
): Promise<PromptAssemblyResult> {
  const assets = getEmbeddedPromptAssets();
  const basePromptId = basePromptIdForRole(input.role);
  const snippetIds = snippetIdsForInput(input);
  const values = runtimeValues(input);
  const publicInsert =
    input.role === "story_implementor"
      ? await loadPublicInsert(input.implementationPromptInsertPath)
      : input.role === "story_verifier"
        ? await loadPublicInsert(input.verifierPromptInsertPath)
        : {};

  const sections = [
    interpolateTemplate(assets.base[basePromptId], values),
    ...snippetIds.map((snippetId) =>
      interpolateTemplate(assets.snippets[snippetId], values)
    ),
    selfReviewSection(input),
    followupSection(input),
    publicInsert.content ? publicInsert.content.trimEnd() : "",
  ].filter((section) => section.length > 0);

  return {
    prompt: `${sections.join("\n\n")}\n`,
    basePromptId,
    snippetIds,
    publicInsertIds: publicInsert.assetId ? [publicInsert.assetId] : [],
  };
}

import { execFile } from "node:child_process";
import { promisify } from "node:util";

import { z } from "zod";

const execFileAsync = promisify(execFile);

export type ProviderName = "claude-code" | "codex" | "copilot";

export interface ProviderExecutionRequest<TResult> {
  prompt: string;
  cwd: string;
  model: string;
  reasoningEffort: string;
  resumeSessionId?: string;
  timeoutMs: number;
  resultSchema?: z.ZodType<TResult>;
}

export interface ProviderExecutionResult<TResult> {
  provider: ProviderName;
  sessionId?: string;
  stdout: string;
  stderr: string;
  exitCode: number;
  parsedResult?: TResult;
  parseError?: string;
  errorCode?: string;
}

export interface ProviderAdapter {
  provider: ProviderName;
  execute<TResult>(
    request: ProviderExecutionRequest<TResult>
  ): Promise<ProviderExecutionResult<TResult>>;
}

function redactSensitiveText(text: string): string {
  return text
    .replace(/\bBearer\s+[A-Za-z0-9._-]+\b/gi, "Bearer [REDACTED]")
    .replace(/\b(token|auth|authorization|api[_-]?key)\s*[:=]\s*\S+/gi, "$1=[REDACTED]");
}

function extractSessionId(value: Record<string, unknown>): string | undefined {
  for (const key of ["sessionId", "session_id"]) {
    const candidate = value[key];
    if (typeof candidate === "string" && candidate.trim().length > 0) {
      return candidate.trim();
    }
  }

  return undefined;
}

function parseNestedJson(value: unknown): unknown {
  if (typeof value !== "string") {
    return value;
  }

  try {
    return JSON.parse(value);
  } catch {
    return undefined;
  }
}

export function parseProviderPayload<TResult>(input: {
  stdout: string;
  resultSchema?: z.ZodType<TResult>;
}): {
  parsedResult?: TResult;
  sessionId?: string;
  parseError?: string;
} {
  const trimmed = input.stdout.trim();
  if (trimmed.length === 0) {
    return {
      parseError: "Provider stdout was empty.",
    };
  }

  let root: unknown;
  try {
    root = JSON.parse(trimmed);
  } catch {
    return {
      parseError: "Provider stdout was not exact JSON.",
    };
  }

  if (!root || typeof root !== "object" || Array.isArray(root)) {
    return {
      parseError: "Provider stdout was not a JSON object.",
    };
  }

  const rootRecord = root as Record<string, unknown>;
  const resultSchema = input.resultSchema ?? z.unknown();
  const direct = resultSchema.safeParse(rootRecord);
  if (direct.success) {
    return {
      parsedResult: direct.data as TResult,
      sessionId: extractSessionId(rootRecord),
    };
  }

  for (const field of ["result", "text"]) {
    const nested = parseNestedJson(rootRecord[field]);
    const parsed = resultSchema.safeParse(nested);
    if (parsed.success) {
      return {
        parsedResult: parsed.data as TResult,
        sessionId: extractSessionId(rootRecord),
      };
    }
  }

  return {
    parseError: "Provider output did not match the expected JSON payload.",
  };
}

export async function runProviderCommand(params: {
  provider: ProviderName;
  executable: string;
  args: string[];
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}): Promise<{
  provider: ProviderName;
  stdout: string;
  stderr: string;
  exitCode: number;
  errorCode?: string;
}> {
  try {
    const result = await execFileAsync(params.executable, params.args, {
      cwd: params.cwd,
      env: {
        ...process.env,
        ...params.env,
      },
      timeout: params.timeoutMs,
    });

    return {
      provider: params.provider,
      stdout: redactSensitiveText(result.stdout.trim()),
      stderr: redactSensitiveText(result.stderr.trim()),
      exitCode: 0,
    };
  } catch (error) {
    const failed = error as {
      code?: string | number;
      stdout?: string;
      stderr?: string;
      message?: string;
    };

    return {
      provider: params.provider,
      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
      stderr: redactSensitiveText(
        failed.stderr?.trim() ?? failed.message ?? String(error)
      ),
      exitCode:
        typeof failed.code === "number" ? failed.code : 1,
      errorCode:
        typeof failed.code === "string" ? failed.code : undefined,
    };
  }
}

