export function createResultEnvelope<T>(input: {
  command: string;
  outcome: string;
  result?: T;
  errors?: CliError[];
  warnings?: string[];
  artifacts?: CliArtifactRef[];
  startedAt: string;
  finishedAt: string;
}) {
