import { readdir, stat } from "node:fs/promises";
import { join, resolve } from "node:path";

import { pathExists, pathReadable } from "./fs-utils";
import { resolveGitRepoRoot } from "./git-repo";
import { inspectResultSchema, type InspectResult } from "./result-contracts";
import { resolveStoryOrder } from "./story-order";

const ALLOWED_TECH_DESIGN_COMPANIONS = [
  "tech-design-cli-runtime.md",
  "tech-design-skill-process.md",
] as const;

async function pathIsDirectory(path: string): Promise<boolean> {
  try {
    return (await stat(path)).isDirectory();
  } catch {
    return false;
  }
}

function resolveTechDesignArtifacts(entries: string[]): {
  techDesignShape: "two-file" | "four-file";
  companionPaths: string[];
  blockers: string[];
} {
  const companionFiles = entries
    .filter(
      (entry) =>
        entry.startsWith("tech-design-") &&
        entry.endsWith(".md") &&
        entry !== "tech-design.md"
    )
    .sort((left, right) => left.localeCompare(right));

  if (companionFiles.length === 0) {
    return {
      techDesignShape: "two-file",
      companionPaths: [],
      blockers: [],
    };
  }

  const allowed = [...ALLOWED_TECH_DESIGN_COMPANIONS].sort((left, right) =>
    left.localeCompare(right)
  );

  if (JSON.stringify(companionFiles) === JSON.stringify(allowed)) {
    return {
      techDesignShape: "four-file",
      companionPaths: companionFiles,
      blockers: [],
    };
  }

  return {
    techDesignShape: "two-file",
    companionPaths: [],
    blockers: [
      "Invalid tech-design companion layout: expected tech-design-cli-runtime.md and tech-design-skill-process.md for the four-file configuration",
    ],
  };
}

export async function inspectSpecPack(specPackRoot: string): Promise<InspectResult> {
  const resolvedRoot = resolve(specPackRoot);
  const epicPath = join(resolvedRoot, "epic.md");
  const techDesignPath = join(resolvedRoot, "tech-design.md");
  const testPlanPath = join(resolvedRoot, "test-plan.md");
  const storiesDir = join(resolvedRoot, "stories");
  const storiesFile = join(resolvedRoot, "stories.md");
  const blockers: string[] = [];
  const notes: string[] = [];

  const repoRoot = await resolveGitRepoRoot(resolvedRoot);
  if (!repoRoot) {
    blockers.push(`Spec-pack root is not inside a git repo: ${resolvedRoot}`);
  }

  if (!(await pathExists(epicPath))) {
    blockers.push("Missing required artifact: epic.md");
  }

  if (!(await pathExists(techDesignPath))) {
    blockers.push("Missing required artifact: tech-design.md");
  }

  if (!(await pathExists(testPlanPath))) {
    blockers.push("Missing required artifact: test-plan.md");
  }

  const storiesDirExists = await pathIsDirectory(storiesDir);
  if (!storiesDirExists && (await pathExists(storiesFile))) {
    blockers.push("Expected stories/ directory but found stories.md");
  } else if (!storiesDirExists) {
    blockers.push("Missing required artifact: stories/");
  }

  const rootEntries = await readdir(resolvedRoot);
  const techDesignArtifacts = resolveTechDesignArtifacts(rootEntries);
  blockers.push(...techDesignArtifacts.blockers);

  const storyOrder = storiesDirExists
    ? await resolveStoryOrder(storiesDir)
    : { status: "ready" as const, stories: [], notes: [] };
  notes.push(...storyOrder.notes);
  const implInsertPath = join(
    resolvedRoot,
    "custom-story-impl-prompt-insert.md"
  );
  const verifierInsertPath = join(
    resolvedRoot,
    "custom-story-verifier-prompt-insert.md"
  );
  const implInsertExists = await pathExists(implInsertPath);
  const verifierInsertExists = await pathExists(verifierInsertPath);

  if (implInsertExists && !(await pathReadable(implInsertPath))) {
    blockers.push(
      "Unreadable prompt insert: custom-story-impl-prompt-insert.md"
    );
  }

  if (verifierInsertExists && !(await pathReadable(verifierInsertPath))) {
    blockers.push(
      "Unreadable prompt insert: custom-story-verifier-prompt-insert.md"
    );
  }

  const status =
    blockers.length > 0
      ? "blocked"
      : storyOrder.status === "needs-user-decision"
        ? "needs-user-decision"
        : "ready";

  const result: InspectResult = {
    status,
    specPackRoot: resolvedRoot,
    techDesignShape: techDesignArtifacts.techDesignShape,
    artifacts: {
      epicPath,
      techDesignPath,
      techDesignCompanionPaths: techDesignArtifacts.companionPaths.map((file) =>
        join(resolvedRoot, file)
      ),
      testPlanPath,
      storiesDir,
    },
    stories: storyOrder.stories,
    inserts: {
      customStoryImplPromptInsert: implInsertExists ? "present" : "absent",
      customStoryVerifierPromptInsert: verifierInsertExists
        ? "present"
        : "absent",
    },
    blockers,
    notes,
  };

  return inspectResultSchema.parse(result);
}

import { relative, resolve } from "node:path";

import { loadConfig } from "c12";
import { z } from "zod";

export const RUN_CONFIG_FILE_NAME = "impl-run.config.json";

export const reasoningEffortSchema = z.enum(["low", "medium", "high", "xhigh"]);
export const primaryHarnessSchema = z.literal("claude-code");
export const secondaryHarnessSchema = z.enum(["codex", "copilot", "none"]);

export const roleAssignmentSchema = z.object({
  secondary_harness: secondaryHarnessSchema,
  model: z.string().min(1),
  reasoning_effort: reasoningEffortSchema,
});

export const epicVerifierAssignmentSchema = roleAssignmentSchema.extend({
  label: z.string().min(1),
});

export const implRunConfigSchema = z
  .object({
    version: z.literal(1),
    primary_harness: primaryHarnessSchema,
    story_implementor: roleAssignmentSchema,
    quick_fixer: roleAssignmentSchema,
    story_verifier_1: roleAssignmentSchema,
    story_verifier_2: roleAssignmentSchema,
    self_review: z.object({
      passes: z.number().int().min(1).max(5),
    }),
    epic_verifiers: z.array(epicVerifierAssignmentSchema).min(1),
    epic_synthesizer: roleAssignmentSchema,
  })
  .superRefine((value, ctx) => {
    if (value.story_implementor.secondary_harness === "copilot") {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message:
          "story_implementor.secondary_harness cannot be copilot in v1",
        path: ["story_implementor", "secondary_harness"],
      });
    }

    const seenLabels = new Set<string>();
    for (const [index, verifier] of value.epic_verifiers.entries()) {
      if (seenLabels.has(verifier.label)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: "Duplicate epic verifier label",
          path: ["epic_verifiers", index, "label"],
        });
      }
      seenLabels.add(verifier.label);
    }
  });

export type ReasoningEffort = z.infer<typeof reasoningEffortSchema>;
export type PrimaryHarness = z.infer<typeof primaryHarnessSchema>;
export type SecondaryHarness = z.infer<typeof secondaryHarnessSchema>;
export type RoleAssignment = z.infer<typeof roleAssignmentSchema>;
export type EpicVerifierAssignment = z.infer<typeof epicVerifierAssignmentSchema>;
export type ImplRunConfig = z.infer<typeof implRunConfigSchema>;

export function resolveRunConfigPath(
  specPackRoot: string,
  configPath?: string
): string {
  if (!configPath) {
    return resolve(specPackRoot, RUN_CONFIG_FILE_NAME);
  }

  return resolve(specPackRoot, configPath);
}

export async function loadRunConfig(input: {
  specPackRoot: string;
  configPath?: string;
}): Promise<ImplRunConfig> {
  const resolvedPath = resolveRunConfigPath(input.specPackRoot, input.configPath);
  const { config } = await loadConfig({
    cwd: resolve(input.specPackRoot),
    configFile: relative(resolve(input.specPackRoot), resolvedPath),
    configFileRequired: true,
    rcFile: false,
    globalRc: false,
    packageJson: false,
    dotenv: false,
    extend: false,
  });

  return implRunConfigSchema.parse(config);
}

